require("dotenv").config();
const sequelize = require("../config/db")
// const Role = require("../models/roleModel");
const Role = require("../models/Role")

const Service = require("../models/Services");


const seedDatabase = async () => {
  try {
    // Verify DB connection and ensure tables exist
    await sequelize.authenticate();
    console.log('Database connection OK');
    await sequelize.sync({ force: false });
    await Role.bulkCreate(
      [
        { name: "Admin" },
        { name: "Service_provider" },
        { name: "Service_seeker" },
        { name: "Gharbeti" }
      ],
      { ignoreDuplicates: true } // prevent duplicates if run multiple times
    );

    const services = [
      { name: "Plumbing" },
      { name: "Electrical" },
      { name: "Carpentry" },
      { name: "Cleaning" },
      { name: "Painting" },
      { name: "Appliance Repair" },
      { name: "Landscaping" },
      { name: "Pest Control" },
      { name: "Moving Services" },
      { name: "Roofing" },
      { name: "सुत्केरी सेवा" }
    ];

    const svcRes = await Service.bulkCreate(services, { ignoreDuplicates: true });
    console.log(`Seeded ${svcRes.length || services.length} services (ignoreDuplicates).`);

    console.log("Base database seeded successfully!");
    return true;
  } catch (err) {
    console.error("Seeding failed:", err && err.message ? err.message : err);
    if (err && err.stack) console.error(err.stack);
    return false;
  }
};

