// Run all seeds in order
(async function runSeeds(){
  const ok = await seedDatabase();
  if (!ok) {
    console.error('Base seeding failed, aborting downstream seeds');
    process.exit(1);
  }
  await seedProvinces();
  await seedLocaiton();
  console.log('All seeding finished');
  process.exit(0);
})();
